using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

using System.ComponentModel.DataAnnotations;

namespace TicketClassifier.Models;

public class TicketRequest
{
    [Required]
    public string Subject { get; set; } = string.Empty;

    [Required]
    public string Description { get; set; } = string.Empty;

    [Range(1, 3)]
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> ConfidenceScores { get; set; } = new();
}

public class ModelMetricsResponse
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public List<CategoryMetric> PerCategoryMetrics { get; set; } = new();
}

public class CategoryMetric
{
    public string Category { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly ModelMetricsResponse _metrics;
    private readonly string[] _categoryLabels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Extract category labels before training
        var categories = _mlContext.Data
            .CreateEnumerable<TicketData>(dataView, reuseRowObject: false)
            .Select(t => t.Category)
            .Distinct()
            .OrderBy(c => c)
            .ToArray();
        _categoryLabels = categories;

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        // Use cross-validation for evaluation on small datasets
        var cvResults = _mlContext.MulticlassClassification
            .CrossValidate(dataView, pipeline, numberOfFolds: 3, labelColumnName: "Label");

        _metrics = BuildMetrics(cvResults);

        // Train final model on all data
        _model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidenceScores = new Dictionary<string, float>();
        for (var i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
        {
            confidenceScores[_categoryLabels[i]] = prediction.Score[i];
        }

        return new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            ConfidenceScores = confidenceScores
        };
    }

    public ModelMetricsResponse GetMetrics() => _metrics;

    private static ModelMetricsResponse BuildMetrics(
        IReadOnlyList<TrainCatalogBase.CrossValidationResult<Microsoft.ML.Data.MulticlassClassificationMetrics>> cvResults)
    {
        var avgMetrics = new ModelMetricsResponse
        {
            MacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy),
            MicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy),
            LogLoss = cvResults.Average(r => r.Metrics.LogLoss),
            LogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction)
        };

        // Aggregate per-class metrics from the best fold
        var bestFold = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First();
        var perClass = bestFold.Metrics.PerClassLogLoss;
        if (perClass != null)
        {
            for (var i = 0; i < perClass.Count; i++)
            {
                avgMetrics.PerCategoryMetrics.Add(new CategoryMetric
                {
                    Category = $"Class {i}",
                    Precision = bestFold.Metrics.ConfusionMatrix.PerClassPrecision[i],
                    Recall = bestFold.Metrics.ConfusionMatrix.PerClassRecall[i],
                    F1Score = 2.0 * bestFold.Metrics.ConfusionMatrix.PerClassPrecision[i]
                             * bestFold.Metrics.ConfusionMatrix.PerClassRecall[i]
                             / (bestFold.Metrics.ConfusionMatrix.PerClassPrecision[i]
                                + bestFold.Metrics.ConfusionMatrix.PerClassRecall[i] + 1e-10)
                });
            }
        }

        return avgMetrics;
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (!ModelState.IsValid)
            return BadRequest(ModelState);

        var result = _classifier.Predict(request);
        return Ok(result);
    }

    [HttpGet("metrics")]
    public ActionResult<ModelMetricsResponse> GetMetrics()
    {
        return Ok(_classifier.GetMetrics());
    }
}

