using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);

var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
if (!File.Exists(dataPath))
    dataPath = Path.Combine(Directory.GetCurrentDirectory(), "Data", "tickets.csv");

builder.Services.AddSingleton(new TicketClassifierService(dataPath));

var app = builder.Build();

app.MapPost("/api/tickets/classify", (TicketRequest request, TicketClassifierService classifier) =>
{
    if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
        return Results.BadRequest("Subject and Description are required.");
    if (request.Priority < 1 || request.Priority > 3)
        return Results.BadRequest("Priority must be between 1 and 3.");

    return Results.Ok(classifier.Predict(request));
});

app.MapGet("/api/tickets/metrics", (TicketClassifierService classifier) =>
{
    return Results.Ok(classifier.GetMetrics());
});

app.Run();

