1. using Microsoft.ML;
2. using TicketClassifier.Models;
3. 
4. namespace TicketClassifier.Services;
5. 
6. public class TicketClassifierService
7. {
8.     private readonly MLContext _mlContext;
9.     private readonly ITransformer _model;
10.     private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
11.     private readonly ModelMetricsResponse _metrics;
12.     private readonly string[] _categoryLabels;
13. 
14.     public TicketClassifierService(string dataPath)
15.     {
16.         _mlContext = new MLContext(seed: 42);
17. 
18.         var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
19.             dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
20. 
21.         // Extract category labels before training
22.         var categories = _mlContext.Data
23.             .CreateEnumerable<TicketData>(dataView, reuseRowObject: false)
24.             .Select(t => t.Category)
25.             .Distinct()
26.             .OrderBy(c => c)
27.             .ToArray();
28.         _categoryLabels = categories;
29. 
30.         var pipeline = _mlContext.Transforms.Conversion
31.                 .MapValueToKey("Label", nameof(TicketData.Category))
32.             .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
33.             .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
34.             .Append(_mlContext.Transforms.Concatenate("Features",
35.                 "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
36.             .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
37.             .Append(_mlContext.MulticlassClassification.Trainers
38.                 .SdcaMaximumEntropy("Label", "Features"))
39.             .Append(_mlContext.Transforms.Conversion
40.                 .MapKeyToValue("PredictedLabel"));
41. 
42.         // Use cross-validation for evaluation on small datasets
43.         var cvResults = _mlContext.MulticlassClassification
44.             .CrossValidate(dataView, pipeline, numberOfFolds: 3, labelColumnName: "Label");
45. 
46.         _metrics = BuildMetrics(cvResults);
47. 
48.         // Train final model on all data
49.         _model = pipeline.Fit(dataView);
50.         _predictionEngine = _mlContext.Model
51.             .CreatePredictionEngine<TicketData, TicketPrediction>(_model);
52.     }
53. 
54.     public TicketPredictionResponse Predict(TicketRequest request)
55.     {
56.         var ticketData = new TicketData
57.         {
58.             Subject = request.Subject,
59.             Description = request.Description,
60.             Priority = request.Priority
61.         };
62. 
63.         var prediction = _predictionEngine.Predict(ticketData);
64. 
65.         var confidenceScores = new Dictionary<string, float>();
66.         for (var i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
67.         {
68.             confidenceScores[_categoryLabels[i]] = prediction.Score[i];
69.         }
70. 
71.         return new TicketPredictionResponse
72.         {
73.             PredictedCategory = prediction.Category,
74.             ConfidenceScores = confidenceScores
75.         };
76.     }
77. 
78.     public ModelMetricsResponse GetMetrics() => _metrics;
79. 
80.     private static ModelMetricsResponse BuildMetrics(
81.         IReadOnlyList<TrainCatalogBase.CrossValidationResult<Microsoft.ML.Data.MulticlassClassificationMetrics>> cvResults)
82.     {
83.         var avgMetrics = new ModelMetricsResponse
84.         {
85.             MacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy),
86.             MicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy),
87.             LogLoss = cvResults.Average(r => r.Metrics.LogLoss),
88.             LogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction)
89.         };
90. 
91.         // Aggregate per-class metrics from the best fold
92.         var bestFold = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First();
93.         var perClass = bestFold.Metrics.PerClassLogLoss;
94.         if (perClass != null)
95.         {
96.             for (var i = 0; i < perClass.Count; i++)
97.             {
98.                 avgMetrics.PerCategoryMetrics.Add(new CategoryMetric
99.                 {
100.                     Category = $"Class {i}",
101.                     Precision = bestFold.Metrics.ConfusionMatrix.PerClassPrecision[i],
102.                     Recall = bestFold.Metrics.ConfusionMatrix.PerClassRecall[i],
103.                     F1Score = 2.0 * bestFold.Metrics.ConfusionMatrix.PerClassPrecision[i]
104.                              * bestFold.Metrics.ConfusionMatrix.PerClassRecall[i]
105.                              / (bestFold.Metrics.ConfusionMatrix.PerClassPrecision[i]
106.                                 + bestFold.Metrics.ConfusionMatrix.PerClassRecall[i] + 1e-10)
107.                 });
108.             }
109.         }
110. 
111.         return avgMetrics;
112.     }
113. }
114.

