using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly ModelMetricsResponse _metrics;
    private readonly string[] _categoryLabels;

    public TicketClassifierService(string dataPath)
    {
        var mlContext = new MLContext(seed: 42);

        var dataView = mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        // Cross-validation for evaluation metrics on small datasets
        var cvResults = mlContext.MulticlassClassification
            .CrossValidate(dataView, pipeline, numberOfFolds: 3, labelColumnName: "Label");

        // Train final model on all data
        var model = pipeline.Fit(dataView);

        // Extract label ordering from the trained model's key-value mapping
        var transformedData = model.Transform(dataView);
        var labelColumn = transformedData.Schema["Label"];
        var keyType = labelColumn.Type as KeyDataViewType;
        VBuffer<ReadOnlyMemory<char>> keyValues = default;
        labelColumn.GetKeyValues(ref keyValues);
        _categoryLabels = keyValues.DenseValues()
            .Select(v => v.ToString())
            .ToArray();

        _predictionEngine = mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(model);

        _metrics = BuildMetrics(cvResults, _categoryLabels);
    }

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidenceScores = new Dictionary<string, float>();
        for (var i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
        {
            confidenceScores[_categoryLabels[i]] = prediction.Score[i];
        }

        return new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            ConfidenceScores = confidenceScores
        };
    }

    public ModelMetricsResponse GetMetrics() => _metrics;

    private static ModelMetricsResponse BuildMetrics(
        IReadOnlyList<TrainCatalogBase.CrossValidationResult<MulticlassClassificationMetrics>> cvResults,
        string[] labels)
    {
        var response = new ModelMetricsResponse
        {
            MacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy),
            MicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy),
            LogLoss = cvResults.Average(r => r.Metrics.LogLoss),
            LogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction)
        };

        var bestFold = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First();
        var cm = bestFold.Metrics.ConfusionMatrix;

        for (var i = 0; i < cm.PerClassPrecision.Count; i++)
        {
            var precision = cm.PerClassPrecision[i];
            var recall = cm.PerClassRecall[i];
            var f1 = (precision + recall) > 0
                ? 2.0 * precision * recall / (precision + recall)
                : 0.0;

            response.PerCategoryMetrics.Add(new CategoryMetric
            {
                Category = i < labels.Length ? labels[i] : $"Class {i}",
                Precision = precision,
                Recall = recall,
                F1Score = f1
            });
        }

        return response;
    }
}

